"""
This module provides functions to compute metrics for geo referenced annotations
"""

import logging
from typing import NamedTuple, Optional, Tuple, Collection

import geopandas as gpd
import pandas as pd

from geosat.geo_annotations.geo_annotations import GeoAnnotations
from geosat.tools.boundingboxes import BoundingBox


class ClassScores(NamedTuple):
    classname: str
    tp: int
    fp: int
    fn: int
    p: float
    r: float
    f1: float
    f2: float


def compute_geo_tp_fp_fn(
    detections: GeoAnnotations,
    ground_truth: GeoAnnotations,
    score_th: float,
    iou_th: float,
) -> Tuple[gpd.GeoDataFrame, gpd.GeoDataFrame, gpd.GeoDataFrame]:
    """
    Returns GeoAnnotations formatted ``GeoDataFrames`` containing information on TPs, FPs, and FNs

    Column names for detections are :
    xmin_det, ymin_det, xmax_det, ymax_det, center_x_det, center_y_det, width_det, height_det, score_det, class_id_det,
    class_name_det, angle_det

    With "_gt" suffix for ground truth
    """

    def iou(r):
        boxa_values = [r.xmin_det, r.ymin_det, r.xmax_det, r.ymax_det]
        boxb_values = [r.xmin_gt, r.ymin_gt, r.xmax_gt, r.ymax_gt]
        if None in boxa_values or None in boxb_values:
            return 0
        boxa = BoundingBox(*boxa_values)
        boxb = BoundingBox(*boxb_values)
        return boxa.intersect_over_union(boxb)

    det_gdf = detections.to_geodataframe("oriented")
    gt_gdf = ground_truth.to_geodataframe("oriented")

    det_gdf = det_gdf.add_suffix("_det").set_geometry("geometry_det")
    gt_gdf = gt_gdf.add_suffix("_gt").set_geometry("geometry_gt")

    if not len(detections) and not len(ground_truth):
        logging.info("Empty GroundObjects when computing metrics")
        return (gpd.GeoDataFrame(),) * 3  # TP, FP, FN are empty
    elif not len(ground_truth):
        logging.info("No Ground Truths when computing metrics")
        # only ground truths, so we return the number of annotations as fn
        return (
            gpd.GeoDataFrame(),
            det_gdf.query(f"score_det >= {score_th}"),
            gpd.GeoDataFrame(),
        )
    elif not len(detections):
        logging.info("No detections when computing metrics")
        # only detections, so we return the number of detections as fp
        return gpd.GeoDataFrame(), gpd.GeoDataFrame(), gt_gdf

    det_gdf = det_gdf.query(f"score_det >= {score_th}")

    intersection_on_det = gpd.sjoin(
        det_gdf, gt_gdf, how="left", lsuffix="det", rsuffix="gt"
    )
    intersection_on_gt = gpd.sjoin(
        gt_gdf, det_gdf, how="left", lsuffix="gt", rsuffix="det"
    )

    intersection_on_det["iou"] = (
        pd.Series([], dtype=float)
        if intersection_on_det.empty
        else intersection_on_det.apply(iou, axis=1)
    )
    intersection_on_gt["iou"] = (
        pd.Series([], dtype=float)
        if intersection_on_gt.empty
        else intersection_on_gt.apply(iou, axis=1)
    )
    intersection_on_det.loc[intersection_on_det["iou"].isna(), "iou"] = 0
    intersection_on_gt.loc[intersection_on_gt["iou"].isna(), "iou"] = 0

    intersection_on_gt = intersection_on_gt.reset_index()
    intersection_on_gt = intersection_on_gt.rename(columns={"index": "index_gt"})
    intersection_on_gt["best_iou_on_gt"] = False
    intersection_on_gt["best_iou_on_det"] = False

    for _, overlaps in intersection_on_gt.groupby("index_gt"):
        overlaps = overlaps.query("class_name_gt == class_name_det")
        if not overlaps.empty:
            iou_max_idx = overlaps["iou"].idxmax()
            intersection_on_gt.loc[iou_max_idx, "best_iou_on_gt"] = True

    for _, overlaps in intersection_on_gt.groupby("index_det"):
        overlaps = overlaps.query("class_name_gt == class_name_det")
        if not overlaps.empty:
            iou_max_idx = overlaps["iou"].idxmax()
            intersection_on_gt.loc[iou_max_idx, "best_iou_on_det"] = True

    # A TP is a true detection, i.e. a detection with the best iou on a GT with same class
    tp_gdf = intersection_on_gt.query(
        f"best_iou_on_gt and best_iou_on_det and iou >= {iou_th}"
    )
    # A FP is a detection which should not have been raised, hence it is all unique detections which are not in TPs gdf
    fp_gdf = intersection_on_det.query(
        # f"(iou < {score_th} or class_name_gt != class_name_det) and det_id not in @tp_gdf.det_id and best_iou"
        "index not in @tp_gdf.index_det"
    )
    # A FN is a GT that should have been detected, however
    fn_gdf = intersection_on_gt.query(
        "index_gt not in @tp_gdf.index_gt"
    )  # index_det not in @tp_gdf.index_det or

    # If many detections on the same ground truth, only one annotation should remain
    fn_gdf = fn_gdf.loc[~fn_gdf.index_gt.duplicated()]
    # If many GT were present under a detection, then we should simplify this dataframe to get
    # a count of unique detections (sjoin duplicates a detection when overlapping with more than 1 GT)
    fp_gdf = fp_gdf.loc[~fp_gdf.index.duplicated()]
    return tp_gdf, fp_gdf, fn_gdf


def compute_metrics(tp, fp, fn):
    """
    Compute more meaningful metrics thanks to FP, TP, FN
    """
    if tp == 0:
        return tp, fp, fn, 0, 0, 0, 0
    p = tp / (tp + fp)
    r = tp / (tp + fn) if tp + fn > 0 else 0
    f1 = 2 * p * r / (p + r)
    f2 = tp / (tp + 0.2 * fp + 0.8 * fn)
    return tp, fp, fn, p, r, f1, f2


def metrics_per_class(
    tp_gdf: pd.DataFrame,
    fp_gdf: pd.DataFrame,
    fn_gdf: pd.DataFrame,
    on_classes: Optional[Collection[str]] = None,
) -> pd.DataFrame:
    """
    Takes ``GeoDataFrame`` generated from ``compute_geo_tp_fp_fn`` and compute metrics per class and for all classes
    """
    scores = []
    if not on_classes:  # If no classes are given then all classes are considered
        on_classes = set()
        if "class_name_gt" in fn_gdf.columns:
            on_classes.update(fn_gdf.class_name_gt.unique())
        if "class_name_det" in fp_gdf.columns:
            on_classes.update(fp_gdf.class_name_det.unique())
        if "class_name_gt" in tp_gdf.columns:
            on_classes.update(tp_gdf.class_name_gt.unique())
        on_classes = {c for c in on_classes if not pd.isna(c)}
    for class_name in on_classes:
        tp = tp_gdf.query(f"class_name_gt == '{class_name}'").shape[0]
        fp = fp_gdf.query(f"class_name_det == '{class_name}'").shape[0]
        fn = fn_gdf.query(f"class_name_gt == '{class_name}'").shape[0]
        class_scores = ClassScores(class_name, *compute_metrics(tp, fp, fn))
        scores.append(class_scores)
    tp = tp_gdf.shape[0]
    fp = fp_gdf.shape[0]
    fn = fn_gdf.shape[0]
    all_classes_scores = ClassScores("ALL_CLASSES", *compute_metrics(tp, fp, fn))
    scores.append(all_classes_scores)
    return pd.DataFrame.from_records(scores, columns=ClassScores._fields)
